99	// SelectCheapestProfile returns the lowest-power profile band that has at least
100	// one available, auto-routable model.
101	func SelectCheapestProfile(snap ProfileSnapshot) string {
102		profiles := satisfiableProfiles(snap, 0)
103		sort.SliceStable(profiles, func(i, j int) bool {
104			left, right := profiles[i], profiles[j]
105			if profileMaxForSort(left) != profileMaxForSort(right) {
106				return profileMaxForSort(left) < profileMaxForSort(right)
107			}
108			if left.MinPower != right.MinPower {
109				return left.MinPower < right.MinPower
110			}
111			return preferProfile(left, right)
112		})
113		if len(profiles) == 0 {
114			return ""
115		}
116		return profiles[0].Name
117	}
