159	func satisfiableProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
160		out := make([]agentlib.PolicyInfo, 0, len(snap.Profiles))
161		for _, profile := range snap.Profiles {
162			if profile.Name == "" {
163				continue
164			}
165			if profile.MinPower == 0 && profile.MaxPower == 0 {
166				continue
167			}
168			if floor > 0 && profile.MinPower < floor {
169				continue
170			}
171			if profileHasAvailableModel(profile, snap.Models) {
172				out = append(out, profile)
