178	func profileHasAvailableModel(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) bool {
179		for _, model := range models {
180			if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
181				continue
182			}
183			if profile.MinPower > 0 && model.Power < profile.MinPower {
184				continue
185			}
186			if profile.MaxPower > 0 && model.Power > profile.MaxPower {
187				continue
188			}
189			return true
190		}
191		return false
192	}
