// countPriorReviewEscalationEvents counts review-error and
// review-pairing-degraded events for beadID scoped to resultRev. Both event
// kinds contribute to reviewer MinPower escalation (ADR-024 P3): a transport/
// empty error signals a failing pool, and a pairing-degraded event signals that
// the reviewer landed on the same provider as the implementer. Each such event
// increments the escalation count that drives the MinPower ladder in
// reviewerDispatchProfile.
func countPriorReviewEscalationEvents(reader ReviewerEventReader, beadID, resultRev string) int {
	if reader == nil || resultRev == "" {
		return 0
	}
	events, err := reader.Events(beadID)
	if err != nil {
		return 0
	}
	n := 0
	for _, ev := range events {
		switch ev.Kind {
		case "review-error", ReviewPairingDegradedEventKind:
			m := reResultRevField.FindStringSubmatch(ev.Body)
			if m != nil && m[1] == resultRev {
				n++
			}
		}
	}
	return n
}

// reviewerEscalatedEventBody is the canonical body for kind:reviewer-escalated
// events. It records the escalation context so operators can correlate
// MinPower bumps with the review-error or pairing-degraded events that
// triggered them.
func reviewerEscalatedEventBody(priorErrors, newMinPower int, resultRev string) string {
	var b strings.Builder
