// reviewerDispatchProfile returns the fizeau profile name and MinPower floor
// to use for the reviewer dispatch. priorErrors is the count of review-error
// and review-pairing-degraded events already recorded for this result_rev; each
// non-zero count adds a ladder step to MinPower (ADR-024 P3 escalation):
//
//	priorErrors == 0: floor = impl.ActualPower + 1  (base)
//	priorErrors == 1: floor = impl.ActualPower + 2  (second attempt)
//	priorErrors >= 2: top-of-ladder profile          (third+ attempt)
//
// The returned MinPower is max(profile.MinPower, escalated floor) so the
// MinPowerOverride applied at dispatch is never less than the escalation
// intent even when the profile's own MinPower is lower.
func (r *DefaultBeadReviewer) reviewerDispatchProfile(ctx context.Context, impl ImplementerRouting, priorErrors int) reviewerDispatchProfile {
	floor := 0
	if impl.ActualPower > 0 {
		switch {
		case priorErrors >= 2:
			// Top-of-ladder: use SelectStrongestProfile below; floor set high
			// as fallback when no snapshot is available.
			floor = impl.ActualPower + 3
		case priorErrors == 1:
			floor = impl.ActualPower + 2
		default:
			floor = impl.ActualPower + 1
		}
	}
	if r.Runner != nil {
		return reviewerDispatchProfile{MinPower: floor}
	}
	selectedSvc := r.Service
	if selectedSvc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(r.ProjectRoot)
		if err != nil {
			return reviewerDispatchProfile{MinPower: floor}
		}
		selectedSvc = built
	}
	snap, err := LoadProfileSnapshot(ctx, selectedSvc)
	if err != nil {
		return reviewerDispatchProfile{MinPower: floor}
	}
	name := ""
	if priorErrors >= 2 {
		// Top-of-ladder: select the strongest available profile regardless of floor.
		name = SelectStrongestProfile(snap)
	} else if floor > 0 {
		name = SelectStrongestProfileAbove(snap, floor)
		if name == "" {
			// Floor exceeds all profiles; fall back to the absolute strongest.
			name = SelectStrongestProfile(snap)
		}
	} else {
		name = selectSmartReviewerProfile(snap)
	}
	if name == "" {
		return reviewerDispatchProfile{MinPower: floor}
	}
	for _, profile := range snap.Profiles {
		if profile.Name == name {
			// Return max(profile.MinPower, floor) so escalation intent is
			// preserved even when the profile's own floor is lower.
			minPower := profile.MinPower
			if floor > minPower {
				minPower = floor
			}
			return reviewerDispatchProfile{Name: name, MinPower: minPower}
		}
	}
	return reviewerDispatchProfile{Name: name, MinPower: floor}
}

