			{ID: "frontier-model", Power: 72, Available: true, AutoRoutable: true},
		},
		executeEvents: []agentlib.ServiceEvent{
			{
				Type: "final",
				Data: []byte(`{"status":"success","final_text":"` +
					`{\"schema_version\":1,\"verdict\":\"APPROVE\",\"summary\":\"ok\",` +
