// TestReviewerEscalation_OnSecondTransportError verifies AC 1+2: after one
// prior review-error event on the same result_rev, reviewerDispatchProfile
// uses MinPower = impl.ActualPower + 2 (one extra ladder step) and the
// dispatched service request carries the escalated floor.
func TestReviewerEscalation_OnSecondTransportError(t *testing.T) {
	resetProfileSnapshotCacheForTest(t)
	projectRoot, head, store := reviewPairingTestSetup(t)
	const resultRev = "aabbccdd"

	// Seed 1 prior review-error event for this result_rev.
	require.NoError(t, store.AppendEvent("ddx-pairing", bead.BeadEvent{
		Kind:    "review-error",
		Summary: evidence.OutcomeReviewTransport,
		Body:    ReviewErrorEventBody(evidence.OutcomeReviewTransport, 1, resultRev, "prior transport failure"),
		Actor:   "worker",
		Source:  "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}))

	svc := escalationTestSvc()
	events := &stubBeadEventAppender{}
	reviewer := &DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   store,
		Service:     svc,
		BeadEvents:  events,
		EventReader: store,
	}

	// ReviewBead uses resultRev=head (the actual commit). We pass head as
	// result_rev but the store event uses "aabbccdd". To make the EventReader
	// count work, we need the impl correlation result_rev to match the seeded
	// event. Use a fresh setup that seeds with the real HEAD.
	const testHead = "aabbccdd"
	// Re-seed with actual head so countPriorReviewEscalationEvents finds it.
	// Reset the bead events and re-seed with head as resultRev.
	_ = head

	// Use a separate store with head as the resultRev for the seeded event.
	projectRoot2, head2, store2 := reviewPairingTestSetup(t)
	require.NoError(t, store2.AppendEvent("ddx-pairing", bead.BeadEvent{
		Kind:    "review-error",
		Summary: evidence.OutcomeReviewTransport,
		Body:    ReviewErrorEventBody(evidence.OutcomeReviewTransport, 1, head2, "prior transport failure"),
		Actor:   "worker",
		Source:  "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}))

	svc2 := escalationTestSvc()
	events2 := &stubBeadEventAppender{}
	reviewer2 := &DefaultBeadReviewer{
		ProjectRoot: projectRoot2,
		BeadStore:   store2,
		Service:     svc2,
		BeadEvents:  events2,
		EventReader: store2,
	}

	_, err := reviewer2.ReviewBead(context.Background(), "ddx-pairing", head2, ImplementerRouting{
		Harness:     "codex",
		Provider:    "openai",
		Model:       "gpt-5",
		ActualPower: 70,
	})
	// The APPROVE verdict may fail to parse (svc returns minimal JSON), but we
	// care only about the dispatched MinPower.
	_ = err
