// TestReviewerEscalation_OnSecondTransportError verifies AC 1+2: after one
// prior review-error event on the same result_rev, reviewerDispatchProfile
// bumps MinPower to impl.ActualPower + 2 (one extra ladder step). The
// dispatched service request must carry the escalated MinPower floor.
func TestReviewerEscalation_OnSecondTransportError(t *testing.T) {
	resetProfileSnapshotCacheForTest(t)
	projectRoot, head, store := reviewPairingTestSetup(t)

	// Seed 1 prior review-error event scoped to the head commit (= resultRev).
	require.NoError(t, store.AppendEvent("ddx-pairing", bead.BeadEvent{
		Kind:      "review-error",
		Summary:   evidence.OutcomeReviewTransport,
		Body:      ReviewErrorEventBody(evidence.OutcomeReviewTransport, 1, head, "simulated transport failure"),
		Actor:     "worker",
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}))

	svc := threeProfileSvc()
	events := &stubBeadEventAppender{}
	reviewer := &DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   store,
		Service:     svc,
		BeadEvents:  events,
		EventReader: store,
	}

	_, err := reviewer.ReviewBead(context.Background(), "ddx-pairing", head, ImplementerRouting{
		Harness:     "codex",
		Provider:    "openai",
		Model:       "gpt-5",
		ActualPower: 70,
	})
	require.NoError(t, err)

	// One prior error: floor = impl.ActualPower + 2 = 72.
	assert.Equal(t, 72, svc.lastReq.MinPower,
		"one prior review-error must bump reviewer MinPower to impl.ActualPower+2")

	// A reviewer-escalated event must be appended before dispatch.
	var escalated *bead.BeadEvent
	for i := range events.events {
		if events.events[i].Event.Kind == ReviewerEscalatedEventKind {
			escalated = &events.events[i].Event
			break
		}
	}
	require.NotNil(t, escalated, "escalation must emit a reviewer-escalated event")
	assert.Contains(t, escalated.Body, "prior_error_count=1")
	assert.Contains(t, escalated.Body, "new_min_power=72")
	assert.Contains(t, escalated.Body, "result_rev="+head)
}

